(function () {
    var container;

    function getContainer() {
        if (!container) {
            container = document.createElement("div");
            container.id = "toast-container";
            container.className = "toast-top-center";
            document.body.appendChild(container);
        }
        return container;
    }

    function show(type, message, sticky, onHidden) {
        var toast = document.createElement("div");
        toast.className = "toast toast-" + type;

        var msg = document.createElement("div");
        msg.className = "toast-message";
        msg.innerHTML = message;

        var close = document.createElement("button");
        close.type = "button";
        close.className = "toast-close-button";
        close.setAttribute("aria-label", "Close");
        close.innerHTML = "&times;";

        var timer;
        var hide = function () {
            if (!toast.parentNode) {
                return;
            }
            toast.parentNode.removeChild(toast);
            if (timer) {
                clearTimeout(timer);
            }
            if (typeof onHidden === "function") {
                onHidden();
            }
        };

        close.addEventListener("click", function (e) {
            e.stopPropagation();
            hide();
        });
        toast.addEventListener("click", hide);

        toast.appendChild(close);
        toast.appendChild(msg);
        getContainer().appendChild(toast);

        if (!sticky) {
            timer = setTimeout(hide, 5000);
        }

        return toast;
    }

    window.toasts = {
        success: function (message) {
            return show("success", message, false);
        },
        error: function (message) {
            return show("error", message, false);
        },
        warning: function (message) {
            return show("warning", message, false);
        },
        info: function (message) {
            return show("info", message, false);
        },
        sticky: function (message, onHidden) {
            return show("warning", message, true, onHidden);
        },
        clear: function () {
            if (container) {
                while (container.firstChild) {
                    container.removeChild(container.firstChild);
                }
            }
        }
    };
})();
